  "inlineSchema": "// QRmenu - Prisma Schema\n// Production-ready database design\n\ngenerator client {\n  provider = \"prisma-client-js\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n  url      = env(\"DATABASE_URL\")\n}\n\n// ─────────────────────────────────────────\n// ENUMS\n// ─────────────────────────────────────────\n\nenum SubscriptionPlan {\n  FREE\n  PRO\n  PREMIUM\n}\n\nenum Language {\n  TR\n  EN\n  AR\n}\n\nenum DeviceType {\n  MOBILE\n  TABLET\n  DESKTOP\n  UNKNOWN\n}\n\n// ─────────────────────────────────────────\n// USERS\n// ─────────────────────────────────────────\n\nmodel User {\n  id            String           @id @default(uuid())\n  email         String           @unique\n  password      String\n  name          String\n  plan          SubscriptionPlan @default(FREE)\n  planExpiresAt DateTime?\n  isActive      Boolean          @default(true)\n  createdAt     DateTime         @default(now())\n  updatedAt     DateTime         @updatedAt\n\n  businesses Business[]\n\n  @@map(\"users\")\n}\n\n// ─────────────────────────────────────────\n// BUSINESSES\n// ─────────────────────────────────────────\n\nmodel Business {\n  id          String   @id @default(uuid())\n  userId      String\n  name        String\n  slug        String   @unique\n  description String?\n  phone       String?\n  address     String?\n  logoUrl     String?\n  coverUrl    String?\n  currency    String   @default(\"TRY\")\n  defaultLang Language @default(TR)\n  socialLinks Json?\n  isActive    Boolean  @default(true)\n  createdAt   DateTime @default(now())\n  updatedAt   DateTime @updatedAt\n\n  user  User   @relation(fields: [userId], references: [id], onDelete: Cascade)\n  menus Menu[]\n\n  @@map(\"businesses\")\n}\n\n// ─────────────────────────────────────────\n// MENUS\n// ─────────────────────────────────────────\n\nmodel Menu {\n  id          String   @id @default(uuid())\n  businessId  String\n  name        String\n  description String?\n  isActive    Boolean  @default(false)\n  isDefault   Boolean  @default(false)\n  themeColor  String   @default(\"#FF6B35\")\n  createdAt   DateTime @default(now())\n  updatedAt   DateTime @updatedAt\n\n  business   Business    @relation(fields: [businessId], references: [id], onDelete: Cascade)\n  categories Category[]\n  qrCodes    QrCode[]\n  analytics  Analytics[]\n\n  @@map(\"menus\")\n}\n\n// ─────────────────────────────────────────\n// CATEGORIES\n// ─────────────────────────────────────────\n\nmodel Category {\n  id          String   @id @default(uuid())\n  menuId      String\n  name        String\n  description String?\n  imageUrl    String?\n  sortOrder   Int      @default(0)\n  isActive    Boolean  @default(true)\n  createdAt   DateTime @default(now())\n  updatedAt   DateTime @updatedAt\n\n  menu         Menu          @relation(fields: [menuId], references: [id], onDelete: Cascade)\n  products     Product[]\n  translations Translation[]\n\n  @@map(\"categories\")\n}\n\n// ─────────────────────────────────────────\n// PRODUCTS\n// ─────────────────────────────────────────\n\nmodel Product {\n  id          String   @id @default(uuid())\n  categoryId  String\n  name        String\n  description String?\n  imageUrl    String?\n  basePrice   Decimal  @db.Decimal(10, 2)\n  calories    Int?\n  allergens   String[]\n  isAvailable Boolean  @default(true)\n  isPopular   Boolean  @default(false)\n  sortOrder   Int      @default(0)\n  createdAt   DateTime @default(now())\n  updatedAt   DateTime @updatedAt\n\n  category     Category      @relation(fields: [categoryId], references: [id], onDelete: Cascade)\n  variants     Variant[]\n  extras       Extra[]\n  translations Translation[]\n\n  @@map(\"products\")\n}\n\n// ─────────────────────────────────────────\n// VARIANTS\n// ─────────────────────────────────────────\n\nmodel Variant {\n  id        String  @id @default(uuid())\n  productId String\n  name      String\n  price     Decimal @db.Decimal(10, 2)\n  isDefault Boolean @default(false)\n  sortOrder Int     @default(0)\n\n  product Product @relation(fields: [productId], references: [id], onDelete: Cascade)\n\n  @@map(\"variants\")\n}\n\n// ─────────────────────────────────────────\n// EXTRAS\n// ─────────────────────────────────────────\n\nmodel Extra {\n  id         String  @id @default(uuid())\n  productId  String\n  name       String\n  price      Decimal @default(0) @db.Decimal(10, 2)\n  isRequired Boolean @default(false)\n  maxSelect  Int     @default(1)\n  sortOrder  Int     @default(0)\n\n  product Product @relation(fields: [productId], references: [id], onDelete: Cascade)\n\n  @@map(\"extras\")\n}\n\n// ─────────────────────────────────────────\n// TRANSLATIONS\n// ─────────────────────────────────────────\n\nmodel Translation {\n  id         String   @id @default(uuid())\n  entityType String // 'category' | 'product'\n  entityId   String\n  categoryId String?\n  productId  String?\n  language   Language\n  field      String // 'name' | 'description'\n  value      String\n\n  category Category? @relation(fields: [categoryId], references: [id], onDelete: Cascade)\n  product  Product?  @relation(fields: [productId], references: [id], onDelete: Cascade)\n\n  @@unique([entityType, entityId, language, field])\n  @@map(\"translations\")\n}\n\n// ─────────────────────────────────────────\n// QR CODES\n// ─────────────────────────────────────────\n\nmodel QrCode {\n  id          String   @id @default(uuid())\n  menuId      String\n  label       String? // e.g. \"Table 1\"\n  tableNumber Int?\n  url         String\n  imageUrl    String?\n  scanCount   Int      @default(0)\n  createdAt   DateTime @default(now())\n\n  menu Menu @relation(fields: [menuId], references: [id], onDelete: Cascade)\n\n  @@map(\"qr_codes\")\n}\n\n// ─────────────────────────────────────────\n// ANALYTICS\n// ─────────────────────────────────────────\n\nmodel Analytics {\n  id          String     @id @default(uuid())\n  menuId      String\n  deviceType  DeviceType @default(UNKNOWN)\n  userAgent   String?\n  ipAddress   String?\n  tableNumber Int?\n  createdAt   DateTime   @default(now())\n\n  menu Menu @relation(fields: [menuId], references: [id], onDelete: Cascade)\n\n  @@map(\"analytics\")\n}\n",
